#include <bits/stdc++.h>
using namespace std;
using ll = long long;

bool isPrime(ll n) {
  if (n == 1) return false;
  if (n == 2) return true;
  if (n % 2 == 0) return false;
  for (ll i = 3; i * i <= n; i += 2) {
    if (n % i == 0) return false;
  }
  return true;
}

ll lb, ub;
int cnt = 0;
void dfs(ll n) {
  if (n > 1e9) return;
  if (lb <= n && n <= ub) cnt++;

  for (int i = 1; i <= 9; i++) {
    ll nxt = stoll(to_string(i) + to_string(n));
    if (isPrime(nxt)) dfs(nxt);
  }
}

